648→	set value(value: T) {
649→		if (this._isDisposed || value === this._disposable.value) {
650→			return;
651→		}
652→		this._disposable.value = value;
653→	}
654→
655→	dispose() {
656→		this._isDisposed = true;
657→		this._disposable.dispose();
658→	}
659→}
