876→	/**
877→	 * Disposes of all stored values and clear the set, but DO NOT mark this object as disposed.
878→	 */
879→	clearAndDisposeAll(): void {
880→		if (!this._store.size) {
881→			return;
882→		}
883→
884→		try {
885→			dispose(this._store.values());
886→		} finally {
887→			this._store.clear();
888→		}
889→	}
