123→export interface SerializedError {
124→	readonly $isError: true;
125→	readonly name: string;
126→	readonly message: string;
127→	readonly stack: string;
128→	readonly noTelemetry: boolean;
129→	readonly code?: string;
130→	readonly cause?: SerializedError;
131→}
132→
133→type ErrorWithCode = Error & {
134→	code: string | undefined;
135→};
136→
137→export function transformErrorForSerialization(error: Error): SerializedError;
138→export function transformErrorForSerialization(error: any): any;
139→export function transformErrorForSerialization(error: any): any {
140→	if (error instanceof Error) {
141→		const { name, message, cause } = error;
142→		// eslint-disable-next-line local/code-no-any-casts
143→		const stack: string = (<any>error).stacktrace || (<any>error).stack;
144→		return {
145→			$isError: true,
146→			name,
147→			message,
148→			stack,
149→			noTelemetry: ErrorNoTelemetry.isErrorNoTelemetry(error),
150→			cause: cause ? transformErrorForSerialization(cause) : undefined,
151→			code: (<ErrorWithCode>error).code
152→		};
153→	}
154→
155→	// return as is
156→	return error;
157→}
158→
159→export function transformErrorFromSerialization(data: SerializedError): Error {
160→	let error: Error;
161→	if (data.noTelemetry) {
162→		error = new ErrorNoTelemetry();
163→	} else {
164→		error = new Error();
165→		error.name = data.name;
166→	}
167→	error.message = data.message;
168→	error.stack = data.stack;
169→	if (data.code) {
170→		(<ErrorWithCode>error).code = data.code;
171→	}
172→	if (data.cause) {
173→		error.cause = transformErrorFromSerialization(data.cause);
174→	}
175→	return error;
176→}
