325→interface IScheduledLater extends IDisposable {
326→	isTriggered(): boolean;
327→}
328→
329→const timeoutDeferred = (timeout: number, fn: () => void): IScheduledLater => {
330→	let scheduled = true;
331→	const handle = setTimeout(() => {
332→		scheduled = false;
333→		fn();
334→	}, timeout);
335→	return {
336→		isTriggered: () => scheduled,
337→		dispose: () => {
338→			clearTimeout(handle);
339→			scheduled = false;
340→		},
341→	};
342→};
343→
344→const microtaskDeferred = (fn: () => void): IScheduledLater => {
345→	let scheduled = true;
346→	queueMicrotask(() => {
347→		if (scheduled) {
348→			scheduled = false;
349→			fn();
350→		}
351→	});
352→
353→	return {
354→		isTriggered: () => scheduled,
355→		dispose: () => { scheduled = false; },
356→	};
357→};
