474→	isTriggered(): boolean {
475→		return this.delayer.isTriggered();
476→	}
477→
478→	cancel(): void {
479→		this.delayer.cancel();
480→	}
481→
482→	dispose(): void {
483→		this.delayer.dispose();
484→		this.throttler.dispose();
485→	}
