798→/**
799→ * Same as `Queue`, ensures that only 1 task is executed at the same time. The difference to `Queue` is that
800→ * there is only 1 task about to be scheduled next. As such, calling `queue` while a task is executing will
801→ * replace the currently queued task until it executes.
802→ *
803→ * As such, the returned promise may not be from the factory that is passed in but from the next factory that
804→ * is running after having called `queue`.
805→ */
806→export class LimitedQueue {
807→
808→	private readonly sequentializer = new TaskSequentializer();
809→
810→	private tasks = 0;
811→
812→	queue(factory: ITask<Promise<void>>): Promise<void> {
813→		if (!this.sequentializer.isRunning()) {
814→			return this.sequentializer.run(this.tasks++, factory());
815→		}
816→
817→		return this.sequentializer.queue(() => {
818→			return this.sequentializer.run(this.tasks++, factory());
819→		});
820→	}
821→}
