937→/**
938→ * Processes tasks in the order they were scheduled.
939→*/
940→export class TaskQueue {
941→	private _runningTask: Task<any> | undefined = undefined;
942→	private _pendingTasks: { task: Task<any>; deferred: DeferredPromise<any>; setUndefinedWhenCleared: boolean }[] = [];
943→
944→	/**
945→	 * Waits for the current and pending tasks to finish, then runs and awaits the given task.
946→	 * If the task is skipped because of clearPending, the promise is rejected with a CancellationError.
947→	*/
948→	public schedule<T>(task: Task<T>): Promise<T> {
949→		const deferred = new DeferredPromise<T>();
950→		this._pendingTasks.push({ task, deferred, setUndefinedWhenCleared: false });
951→		this._runIfNotRunning();
952→		return deferred.p;
953→	}
954→
955→	/**
956→	 * Waits for the current and pending tasks to finish, then runs and awaits the given task.
957→	 * If the task is skipped because of clearPending, the promise is resolved with undefined.
958→	*/
959→	public scheduleSkipIfCleared<T>(task: Task<T>): Promise<T | undefined> {
960→		const deferred = new DeferredPromise<T>();
961→		this._pendingTasks.push({ task, deferred, setUndefinedWhenCleared: true });
962→		this._runIfNotRunning();
963→		return deferred.p;
964→	}
965→
966→	private _runIfNotRunning(): void {
967→		if (this._runningTask === undefined) {
968→			this._processQueue();
969→		}
970→	}
971→
972→	private async _processQueue(): Promise<void> {
973→		if (this._pendingTasks.length === 0) {
974→			return;
975→		}
976→
977→		const next = this._pendingTasks.shift();
978→		if (!next) {
979→			return;
980→		}
981→
982→		if (this._runningTask) {
983→			throw new BugIndicatingError();
984→		}
985→
986→		this._runningTask = next.task;
987→
988→		try {
989→			const result = await next.task();
990→			next.deferred.complete(result);
991→		} catch (e) {
992→			next.deferred.error(e);
993→		} finally {
994→			this._runningTask = undefined;
995→			this._processQueue();
996→		}
997→	}
