999→	/**

500→	 * // the event after a timeout such that multiple listeners attached before
501→	 * // the timeout would receive the event
502→	 * this.onInstallExtension = Event.buffer(service.onInstallExtension, true);
503→	 * ```
504→	 */
505→	export function buffer<T>(event: Event<T>, flushAfterTimeout = false, _buffer: T[] = [], disposable?: DisposableStore): Event<T> {
506→		let buffer: T[] | null = _buffer.slice();
507→
508→		let listener: IDisposable | null = event(e => {
509→			if (buffer) {
510→				buffer.push(e);
511→			} else {
512→				emitter.fire(e);
513→			}
514→		});
515→
516→		if (disposable) {
517→			disposable.add(listener);
518→		}
519→
520→		const flush = () => {
521→			buffer?.forEach(e => emitter.fire(e));
522→			buffer = null;
523→		};
524→
525→		const emitter = new Emitter<T>({
526→			onWillAddFirstListener() {
527→				if (!listener) {
528→					listener = event(e => emitter.fire(e));
529→					if (disposable) {
530→						disposable.add(listener);
531→					}
532→				}
533→			},
534→
535→			onDidAddFirstListener() {
536→				if (buffer) {
537→					if (flushAfterTimeout) {
538→						setTimeout(flush);
539→					} else {
540→						flush();
541→					}
542→				}
543→			},
544→
545→			onDidRemoveLastListener() {
546→				if (listener) {
547→					listener.dispose();
548→				}
549→				listener = null;
550→			}
551→		});
552→
553→		if (disposable) {
554→			disposable.add(emitter);
555→		}
556→
557→		return emitter.event;
558→	}
559→	/**
560→	 * Wraps the event in an {@link IChainableEvent}, allowing a more functional programming style.
561→	 *
562→	 * @example
563→	 * ```
564→	 * // Normal
565→	 * const onEnterPressNormal = Event.filter(
566→	 *   Event.map(onKeyPress.event, e => new StandardKeyboardEvent(e)),
567→	 *   e.keyCode === KeyCode.Enter
568→	 * ).event;
569→	 *
570→	 * // Using chain
571→	 * const onEnterPressChain = Event.chain(onKeyPress.event, $ => $
572→	 *   .map(e => new StandardKeyboardEvent(e))
573→	 *   .filter(e => e.keyCode === KeyCode.Enter)
574→	 * );
575→	 * ```
576→	 */
577→	export function chain<T, R>(event: Event<T>, sythensize: ($: IChainableSythensis<T>) => IChainableSythensis<R>): Event<R> {
578→		const fn: Event<R> = (listener, thisArgs, disposables) => {
579→			const cs = sythensize(new ChainableSynthesis()) as ChainableSynthesis;
580→			return event(function (value) {
581→				const result = cs.evaluate(value);
582→				if (result !== HaltChainable) {
583→					listener.call(thisArgs, result);
584→				}
585→			}, undefined, disposables);
586→		};
587→
588→		return fn;
589→	}
