591→	const HaltChainable = Symbol('HaltChainable');
592→
593→	class ChainableSynthesis implements IChainableSythensis<any> {
594→		private readonly steps: ((input: any) => unknown)[] = [];
595→
596→		map<O>(fn: (i: any) => O): this {
597→			this.steps.push(fn);
598→			return this;
599→		}
600→
601→		forEach(fn: (i: any) => void): this {
602→			this.steps.push(v => {
603→				fn(v);
604→				return v;
605→			});
606→			return this;
607→		}
608→
609→		filter(fn: (e: any) => boolean): this {
610→			this.steps.push(v => fn(v) ? v : HaltChainable);
611→			return this;
612→		}
613→
614→		reduce<R>(merge: (last: R | undefined, event: any) => R, initial?: R | undefined): this {
615→			let last = initial;
616→			this.steps.push(v => {
617→				last = merge(last, v);
618→				return last;
619→			});
620→			return this;
621→		}
622→
623→		latch(equals: (a: any, b: any) => boolean = (a, b) => a === b): ChainableSynthesis {
624→			let firstCall = true;
625→			let cache: any;
626→			this.steps.push(value => {
627→				const shouldEmit = firstCall || !equals(value, cache);
628→				firstCall = false;
629→				cache = value;
630→				return shouldEmit ? value : HaltChainable;
631→			});
632→
633→			return this;
634→		}
635→
636→		public evaluate(value: any) {
637→			for (const step of this.steps) {
638→				value = step(value);
639→				if (value === HaltChainable) {
640→					break;
641→				}
642→			}
643→
644→			return value;
645→		}
646→	}
