753→		readonly emitter: Emitter<T>;
754→
755→		private _counter = 0;
756→		private _hasChanged = false;
757→
758→		constructor(readonly _observable: IObservable<T>, store: DisposableStore | undefined) {
759→			const options: EmitterOptions = {
760→				onWillAddFirstListener: () => {
761→					_observable.addObserver(this);
762→
763→					// Communicate to the observable that we received its current value and would like to be notified about future changes.
764→					this._observable.reportChanges();
765→				},
766→				onDidRemoveLastListener: () => {
767→					_observable.removeObserver(this);
768→				}
769→			};
770→			if (!store) {
771→				_addLeakageTraceLogic(options);
772→			}
773→			this.emitter = new Emitter<T>(options);
774→			if (store) {
775→				store.add(this.emitter);
776→			}
777→		}
778→
779→		beginUpdate<T>(_observable: IObservable<T>): void {
780→			// assert(_observable === this.obs);
781→			this._counter++;
782→		}
783→
784→		handlePossibleChange<T>(_observable: IObservable<T>): void {
785→			// assert(_observable === this.obs);
786→		}
787→
788→		handleChange<T, TChange>(_observable: IObservableWithChange<T, TChange>, _change: TChange): void {
789→			// assert(_observable === this.obs);
790→			this._hasChanged = true;
791→		}
792→
793→		endUpdate<T>(_observable: IObservable<T>): void {
794→			// assert(_observable === this.obs);
795→			this._counter--;
796→			if (this._counter === 0) {
797→				this._observable.reportChanges();
798→				if (this._hasChanged) {
799→					this._hasChanged = false;
800→					this.emitter.fire(this._observable.get());
801→				}
802→			}
803→		}
804→	}
805→
806→	/**
807→	 * Creates an event emitter that is fired when the observable changes.
808→	 * Each listeners subscribes to the emitter.
809→	 */
810→	export function fromObservable<T>(obs: IObservable<T>, store?: DisposableStore): Event<T> {
811→		const observer = new EmitterObserver(obs, store);
812→		return observer.emitter.event;
813→	}
814→
815→	/**
816→	 * Each listener is attached to the observable directly.
817→	 */
818→	export function fromObservableLight(observable: IObservable<unknown>): Event<void> {
819→		return (listener, thisArgs, disposables) => {
820→			let count = 0;
821→			let didChange = false;
822→			const observer: IObserver = {
823→				beginUpdate() {
824→					count++;
825→				},
826→				endUpdate() {
827→					count--;
828→					if (count === 0) {
829→						observable.reportChanges();
830→						if (didChange) {
831→							didChange = false;
832→							listener.call(thisArgs);
833→						}
834→					}
835→				},
836→				handlePossibleChange() {
837→					// noop
838→				},
839→				handleChange() {
840→					didChange = true;
841→				}
842→			};
843→			observable.addObserver(observer);
844→			observable.reportChanges();
845→			const disposable = {
846→				dispose() {
847→					observable.removeObserver(observer);
848→				}
849→			};
850→
851→			addToDisposables(disposable, disposables);
852→
853→			return disposable;
854→		};
855→	}
856→}
