1184→export class ProcessTimeRunOnceScheduler {
1185→
1186→	private runner: (() => void) | null;
1187→	private timeout: number;
1188→
1189→	private counter: number;
1190→	private intervalToken: Timeout | undefined;
1191→	private intervalHandler: () => void;
1192→
1193→	constructor(runner: () => void, delay: number) {
1194→		if (delay % 1000 !== 0) {
1195→			console.warn(`ProcessTimeRunOnceScheduler resolution is 1s, ${delay}ms is not a multiple of 1000ms.`);
1196→		}
1197→		this.runner = runner;
1198→		this.timeout = delay;
1199→		this.counter = 0;
1200→		this.intervalToken = undefined;
1201→		this.intervalHandler = this.onInterval.bind(this);
1202→	}
1203→
1204→	dispose(): void {
1205→		this.cancel();
1206→		this.runner = null;
1207→	}
1208→
1209→	cancel(): void {
1210→		if (this.isScheduled()) {
1211→			clearInterval(this.intervalToken);
1212→			this.intervalToken = undefined;
1213→		}
1214→	}
1215→
1216→	/**
1217→	 * Cancel previous runner (if any) & schedule a new runner.
1218→	 */
1219→	schedule(delay = this.timeout): void {
1220→		if (delay % 1000 !== 0) {
1221→			console.warn(`ProcessTimeRunOnceScheduler resolution is 1s, ${delay}ms is not a multiple of 1000ms.`);
1222→		}
1223→		this.cancel();
1224→		this.counter = Math.ceil(delay / 1000);
1225→		this.intervalToken = setInterval(this.intervalHandler, 1000);
