1468→			return {
1469→				dispose() {
1470→					if (disposed) {
1471→						return;
1472→					}
1473→					disposed = true;
1474→				}
1475→			};
1476→		};
1477→	} else {
1478→		_runWhenIdle = (targetWindow: typeof safeGlobal, runner, timeout?) => {
1479→			const handle: number = targetWindow.requestIdleCallback(runner, typeof timeout === 'number' ? { timeout } : undefined);
1480→			let disposed = false;
1481→			return {
1482→				dispose() {
1483→					if (disposed) {
1484→						return;
1485→					}
1486→					disposed = true;
1487→					targetWindow.cancelIdleCallback(handle);
1488→				}
1489→			};
1490→		};
1491→	}
1492→	runWhenGlobalIdle = (runner, timeout) => _runWhenIdle(globalThis, runner, timeout);
