1568→//#region Task Sequentializer
1569→
1570→interface IRunningTask {
1571→	readonly taskId: number;
1572→	readonly cancel: () => void;
1573→	readonly promise: Promise<void>;
1574→}
1575→
1576→interface IQueuedTask {
1577→	readonly promise: Promise<void>;
1578→	readonly promiseResolve: () => void;
1579→	readonly promiseReject: (error: Error) => void;
1580→	run: ITask<Promise<void>>;
1581→}
1582→
1583→export interface ITaskSequentializerWithRunningTask {
1584→	readonly running: Promise<void>;
1585→}
1586→
1587→export interface ITaskSequentializerWithQueuedTask {
1588→	readonly queued: IQueuedTask;
1589→}
1590→
1591→/**
1592→ * @deprecated use `LimitedQueue` instead for an easier to use API
1593→ */
1594→export class TaskSequentializer {
1595→
1596→	private _running?: IRunningTask;
1597→	private _queued?: IQueuedTask;
1598→
1599→	isRunning(taskId?: number): this is ITaskSequentializerWithRunningTask {
1600→		if (typeof taskId === 'number') {
1601→			return this._running?.taskId === taskId;
1602→		}
1603→
1604→		return !!this._running;
1605→	}
1606→
1607→	get running(): Promise<void> | undefined {
1608→		return this._running?.promise;
1609→	}
1610→
1611→	cancelRunning(): void {
1612→		this._running?.cancel();
1613→	}
1614→
1615→	run(taskId: number, promise: Promise<void>, onCancel?: () => void,): Promise<void> {
1616→		this._running = { taskId, cancel: () => onCancel?.(), promise };
1617→
1618→		promise.then(() => this.doneRunning(taskId), () => this.doneRunning(taskId));
1619→
1620→		return promise;
1621→	}
1622→
1623→	private doneRunning(taskId: number): void {
1624→		if (this._running && taskId === this._running.taskId) {
1625→
1626→			// only set running to done if the promise finished that is associated with that taskId
1627→			this._running = undefined;
1628→
1629→			// schedule the queued task now that we are free if we have any
1630→			this.runQueued();
1631→		}
1632→	}
1633→
1634→	private runQueued(): void {
1635→		if (this._queued) {
1636→			const queued = this._queued;
1637→			this._queued = undefined;
1638→
1639→			// Run queued task and complete on the associated promise
1640→			queued.run().then(queued.promiseResolve, queued.promiseReject);
1641→		}
1642→	}
1643→
1644→	/**
1645→	 * Note: the promise to schedule as next run MUST itself call `run`.
1646→	 *       Otherwise, this sequentializer will report `false` for `isRunning`
1647→	 *       even when this task is running. Missing this detail means that
1648→	 *       suddenly multiple tasks will run in parallel.
1649→	 */
1650→	queue(run: ITask<Promise<void>>): Promise<void> {
1651→
1652→		// this is our first queued task, so we create associated promise with it
1653→		// so that we can return a promise that completes when the task has
1654→		// completed.
1655→		if (!this._queued) {
1656→			const { promise, resolve: promiseResolve, reject: promiseReject } = promiseWithResolvers<void>();
1657→			this._queued = {
1658→				run,
1659→				promise,
1660→				promiseResolve,
1661→				promiseReject
1662→			};
1663→		}
1664→
1665→		// we have a previous queued task, just overwrite it
1666→		else {
1667→			this._queued.run = run;
1668→		}
1669→
1670→		return this._queued.promise;
1671→	}
1672→
1673→	hasQueued(): this is ITaskSequentializerWithQueuedTask {
1674→		return !!this._queued;
1675→	}
1676→
1677→	async join(): Promise<void> {
1678→		return this._queued?.promise ?? this._running?.promise;
1679→	}
1680→}
