1685→
1686→/**
1687→ * The `IntervalCounter` allows to count the number
1688→ * of calls to `increment()` over a duration of
1689→ * `interval`. This utility can be used to conditionally
1690→ * throttle a frequent task when a certain threshold
1691→ * is reached.
1692→ */
1693→export class IntervalCounter {
1694→
1695→	private lastIncrementTime = 0;
1696→
1697→	private value = 0;
1698→
1699→	constructor(private readonly interval: number, private readonly nowFn = () => Date.now()) { }
1700→
1701→	increment(): number {
1702→		const now = this.nowFn();
1703→
1704→		// We are outside of the range of `interval` and as such
1705→		// start counting from 0 and remember the time
1706→		if (now - this.lastIncrementTime > this.interval) {
1707→			this.lastIncrementTime = now;
1708→			this.value = 0;
1709→		}
1710→
1711→		this.value++;
1712→
1713→		return this.value;
1714→	}
1715→}
