1808→export namespace Promises {
1809→
1810→	/**
1811→	 * A drop-in replacement for `Promise.all` with the only difference
1812→	 * that the method awaits every promise to either fulfill or reject.
1813→	 *
1814→	 * Similar to `Promise.all`, only the first error will be returned
1815→	 * if any.
1816→	 */
1817→	export async function settled<T>(promises: Promise<T>[]): Promise<T[]> {
1818→		let firstError: Error | undefined = undefined;
1819→
1820→		const result = await Promise.all(promises.map(promise => promise.then(value => value, error => {
1821→			if (!firstError) {
1822→				firstError = error;
1823→			}
1824→
1825→			return undefined; // do not rethrow so that other promises can settle
1826→		})));
1827→
1828→		if (typeof firstError !== 'undefined') {
1829→			throw firstError;
1830→		}
1831→
1832→		return result as unknown as T[]; // cast is needed and protected by the `throw` above
1833→	}
1834→
1835→	/**
1836→	 * A helper to create a new `Promise<T>` with a body that is a promise
1837→	 * itself. By default, an error that raises from the async body will
1838→	 * end up as a unhandled rejection, so this utility properly awaits the
1839→	 * body and rejects the promise as a normal promise does without async
1840→	 * body.
1841→	 *
1842→	 * This method should only be used in rare cases where otherwise `async`
1843→	 * cannot be used (e.g. when callbacks are involved that require this).
1844→	 */
1845→	export function withAsyncBody<T, E = Error>(bodyFn: (resolve: (value: T) => unknown, reject: (error: E) => unknown) => Promise<unknown>): Promise<T> {
1846→		// eslint-disable-next-line no-async-promise-executor
1847→		return new Promise<T>(async (resolve, reject) => {
1848→			try {
1849→				await bodyFn(resolve, reject);
1850→			} catch (error) {
1851→				reject(error);
1852→			}
1853→		});
1854→	}
1855→}
1856→
1857→export class StatefulPromise<T> {
1858→	private _value: T | undefined = undefined;
1859→	get value(): T | undefined { return this._value; }
1860→
1861→	private _error: unknown = undefined;
1862→	get error(): unknown { return this._error; }
1863→
1864→	private _isResolved = false;
1865→	get isResolved() { return this._isResolved; }
1866→
1867→	public readonly promise: Promise<T>;
1868→
1869→	constructor(promise: Promise<T>) {
1870→		this.promise = promise.then(
1871→			value => {
1872→				this._value = value;
1873→				this._isResolved = true;
1874→				return value;
1875→			},
1876→			error => {
1877→				this._error = error;
1878→				this._isResolved = true;
1879→				throw error;
1880→			}
1881→		);
1882→	}
1883→
1884→	/**
1885→	 * Returns the resolved value.
1886→	 * Throws if the promise is not resolved yet.
1887→	 */
1888→	public requireValue(): T {
1889→		if (!this._isResolved) {
1890→			throw new BugIndicatingError('Promise is not resolved yet');
1891→		}
1892→		if (this._error) {
1893→			throw this._error;
1894→		}
1895→		return this._value!;
1896→	}
1897→}
1898→
1899→export class LazyStatefulPromise<T> {
1900→	private readonly _promise = new Lazy(() => new StatefulPromise(this._compute()));
1901→
1902→	constructor(
1903→		private readonly _compute: () => Promise<T>,
1904→	) { }
1905→
1906→	/**
1907→	 * Returns the resolved value.
1908→	 * Throws if the promise is not resolved yet.
1909→	 */
1910→	public requireValue(): T {
1911→		return this._promise.value.requireValue();
1912→	}
1913→
1914→	/**
1915→	 * Returns the promise (and triggers a computation of the promise if not yet done so).
1916→	 */
1917→	public getPromise(): Promise<T> {
1918→		return this._promise.value.promise;
1919→	}
1920→
1921→	/**
1922→	 * Reads the current value without triggering a computation of the promise.
1923→	 */
1924→	public get currentValue(): T | undefined {
1925→		return this._promise.rawValue?.value;
1926→	}
1927→}
