1939→/**
1940→ * An object that allows to emit async values asynchronously or bring the iterable to an error state using `reject()`.
1941→ * This emitter is valid only for the duration of the executor (until the promise returned by the executor settles).
1942→ */
1943→export interface AsyncIterableEmitter<T> {
1944→	/**
1945→	 * The value will be appended at the end.
1946→	 *
1947→	 * **NOTE** If `reject()` has already been called, this method has no effect.
1948→	 */
1949→	emitOne(value: T): void;
1950→	/**
1951→	 * The values will be appended at the end.
1952→	 *
1953→	 * **NOTE** If `reject()` has already been called, this method has no effect.
1954→	 */
1955→	emitMany(values: T[]): void;
1956→	/**
1957→	 * Writing an error will permanently invalidate this iterable.
1958→	 * The current users will receive an error thrown, as will all future users.
1959→	 *
1960→	 * **NOTE** If `reject()` have already been called, this method has no effect.
1961→	 */
