1978→export class AsyncIterableObject<T> implements AsyncIterable<T> {
1979→
1980→	public static fromArray<T>(items: T[]): AsyncIterableObject<T> {
1981→		return new AsyncIterableObject<T>((writer) => {
1982→			writer.emitMany(items);
1983→		});
