1499→export class DebounceEmitter<T> extends PauseableEmitter<T> {
1500→
1501→	private readonly _delay: number;
1502→	private _handle: Timeout | undefined;
1503→
1504→	constructor(options: EmitterOptions & { merge: (input: T[]) => T; delay?: number }) {
1505→		super(options);
1506→		this._delay = options.delay ?? 100;
1507→	}
1508→
1509→	override fire(event: T): void {
1510→		if (!this._handle) {
1511→			this.pause();
1512→			this._handle = setTimeout(() => {
1513→				this._handle = undefined;
1514→				this.resume();
1515→			}, this._delay);
1516→		}
1517→		super.fire(event);
1518→	}
1519→}
1520→
1521→/**
1522→ * An emitter which queue all events and then process them at the
1523→ * end of the event loop.
1524→ */
1525→export class MicrotaskEmitter<T> extends Emitter<T> {
1526→	private _queuedEvents: T[] = [];
1527→	private _mergeFn?: (input: T[]) => T;
1528→
1529→	constructor(options?: EmitterOptions & { merge?: (input: T[]) => T }) {
1530→		super(options);
1531→		this._mergeFn = options?.merge;
1532→	}
1533→	override fire(event: T): void {
1534→
1535→		if (!this.hasListeners()) {
1536→			return;
1537→		}
1538→
1539→		this._queuedEvents.push(event);
1540→		if (this._queuedEvents.length === 1) {
1541→			queueMicrotask(() => {
1542→				if (this._mergeFn) {
1543→					super.fire(this._mergeFn(this._queuedEvents));
1544→				} else {
1545→					this._queuedEvents.forEach(e => super.fire(e));
1546→				}
1547→				this._queuedEvents = [];
1548→			});
1549→		}
1550→	}
1551→}
