1553→/**
1554→ * An event emitter that multiplexes many events into a single event.
1555→ *
1556→ * @example Listen to the `onData` event of all `Thing`s, dynamically adding and removing `Thing`s
1557→ * to the multiplexer as needed.
1558→ *
1559→ * ```typescript
1560→ * const anythingDataMultiplexer = new EventMultiplexer<{ data: string }>();
1561→ *
1562→ * const thingListeners = DisposableMap<Thing, IDisposable>();
1563→ *
1564→ * thingService.onDidAddThing(thing => {
1565→ *   thingListeners.set(thing, anythingDataMultiplexer.add(thing.onData);
1566→ * });
1567→ * thingService.onDidRemoveThing(thing => {
1568→ *   thingListeners.deleteAndDispose(thing);
1569→ * });
1570→ *
1571→ * anythingDataMultiplexer.event(e => {
1572→ *   console.log('Something fired data ' + e.data)
1573→ * });
1574→ * ```
1575→ */
1576→export class EventMultiplexer<T> implements IDisposable {
1577→
1578→	private readonly emitter: Emitter<T>;
1579→	private hasListeners = false;
1580→	private events: { event: Event<T>; listener: IDisposable | null }[] = [];
1581→
1582→	constructor() {
1583→		this.emitter = new Emitter<T>({
1584→			onWillAddFirstListener: () => this.onFirstListenerAdd(),
1585→			onDidRemoveLastListener: () => this.onLastListenerRemove()
1586→		});
1587→	}
1588→
1589→	get event(): Event<T> {
1590→		return this.emitter.event;
1591→	}
1592→
1593→	add(event: Event<T>): IDisposable {
1594→		const e = { event: event, listener: null };
1595→		this.events.push(e);
1596→
1597→		if (this.hasListeners) {
1598→			this.hook(e);
1599→		}
1600→
1601→		const dispose = () => {
1602→			if (this.hasListeners) {
1603→				this.unhook(e);
1604→			}
1605→
1606→			const idx = this.events.indexOf(e);
1607→			this.events.splice(idx, 1);
1608→		};
1609→
1610→		return toDisposable(createSingleCallFunction(dispose));
1611→	}
1612→
1613→	private onFirstListenerAdd(): void {
1614→		this.hasListeners = true;
1615→		this.events.forEach(e => this.hook(e));
1616→	}
1617→
1618→	private onLastListenerRemove(): void {
1619→		this.hasListeners = false;
1620→		this.events.forEach(e => this.unhook(e));
1621→	}
1622→
1623→	private hook(e: { event: Event<T>; listener: IDisposable | null }): void {
1624→		e.listener = e.event(r => this.emitter.fire(r));
1625→	}
1626→
1627→	private unhook(e: { event: Event<T>; listener: IDisposable | null }): void {
1628→		e.listener?.dispose();
1629→		e.listener = null;
1630→	}
1631→
1632→	dispose(): void {
1633→		this.emitter.dispose();
1634→
1635→		for (const e of this.events) {
1636→			e.listener?.dispose();
1637→		}
1638→		this.events = [];
1639→	}
1640→}
