1642→export interface IDynamicListEventMultiplexer<TEventType> extends IDisposable {
1643→	readonly event: Event<TEventType>;
1644→}
1645→export class DynamicListEventMultiplexer<TItem, TEventType> implements IDynamicListEventMultiplexer<TEventType> {
1646→	private readonly _store = new DisposableStore();
1647→
1648→	readonly event: Event<TEventType>;
1649→
1650→	constructor(
1651→		items: TItem[],
1652→		onAddItem: Event<TItem>,
1653→		onRemoveItem: Event<TItem>,
1654→		getEvent: (item: TItem) => Event<TEventType>
1655→	) {
1656→		const multiplexer = this._store.add(new EventMultiplexer<TEventType>());
1657→		const itemListeners = this._store.add(new DisposableMap<TItem, IDisposable>());
1658→
1659→		function addItem(instance: TItem) {
1660→			itemListeners.set(instance, multiplexer.add(getEvent(instance)));
1661→		}
1662→
1663→		// Existing items
1664→		for (const instance of items) {
1665→			addItem(instance);
1666→		}
1667→
1668→		// Added items
1669→		this._store.add(onAddItem(instance => {
1670→			addItem(instance);
1671→		}));
1672→
1673→		// Removed items
1674→		this._store.add(onRemoveItem(instance => {
1675→			itemListeners.deleteAndDispose(instance);
1676→		}));
1677→
1678→		this.event = multiplexer.event;
1679→	}
1680→
1681→	dispose() {
1682→		this._store.dispose();
1683→	}
1684→}
